import{_ as a,o,c as t,a3 as l}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"153. In Charge Allowances","description":"","frontmatter":{"title":"153. In Charge Allowances","eba":"Mental Health Services 2024-2028","topics":["allowances"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/153-in-charge-allowances.md","filePath":"ebas/mental-health/support-services/preliminary/153-in-charge-allowances.md"}'),r={name:"ebas/mental-health/support-services/preliminary/153-in-charge-allowances.md"};function n(s,e,c,h,i,p){return o(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="_153-in-charge-allowances" tabindex="-1">153. In Charge Allowances <a class="header-anchor" href="#_153-in-charge-allowances" aria-label="Permalink to &quot;153. In Charge Allowances&quot;">​</a></h1><p><strong>153.1</strong> An Employee shall be paid an In-charge Allowance where they are appointed or delegated to exercise control over other Employees, as follows: Extent of control: % Allowance In charge of 1 to 9 other Employees 7% In charge of 10 to 29 other Employees 10% In charge of 30 or more Employees 15%</p><p><strong>153.2</strong> Provided that clause 153.1 does not apply to the following classifications of Employee:</p><p><strong>(a)</strong> General Service Supervisor</p><p><strong>(b)</strong> Food Services Supervisor</p><p><strong>153.3</strong> The percentage In-charge Allowance is calculated on the base rate payable to the Employee pursuant to <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>153.4</strong> The In-Charge Allowance shall be additional to any other allowance to which the Employee is entitled under Section 4.</p>',7)])])}const m=a(r,[["render",n]]);export{d as __pageData,m as default};
